INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_sinalizacao' LIMIT 1), 'Motorista autuado por desrespeitar placa de regulamentação alega, em defesa, que a sinalização vertical estava apagada e mal posicionada, dificultando a leitura. O órgão de trânsito com circunscrição sobre a via reconhece a insuficiência da sinalização. À luz do CTB, assinale a alternativa INCORRETA:', 'Não serão aplicadas sanções por inobservância à sinalização quando esta for insuficiente ou incorreta.', 'O órgão ou entidade de trânsito com circunscrição sobre a via responde pela falta ou incorreta colocação da sinalização.', 'A insuficiência da sinalização impede a aplicação das sanções previstas no CTB ao condutor autuado.', 'Reconhecida a falha na sinalização, as sanções devem ser aplicadas normalmente, cabendo ao condutor exigir apenas a correção da via.', NULL, 'D', 'caso_pratico', 'incorreta', 2, '{"o_que_testa":"Efeito da sinalização insuficiente ou incorreta sobre a aplicação de sanções e responsabilidade do órgão de trânsito.","fundamento_legal":"CTB, art. 90: não serão aplicadas as sanções previstas neste Código por inobservância à sinalização quando esta for insuficiente ou incorreta. § 1º: o órgão ou entidade de trânsito com circunscrição sobre a via é responsável pela implantação da sinalização.","passo_a_passo":["Comando INCORRETA: busca a afirmativa falsa.","A) Verdadeira — caput do art. 90 (não é gabarito porque pede a incorreta).","B) Verdadeira — art. 90, § 1º.","C) Verdadeira — consequência do caput do art. 90.","D) Falsa — com sinalização insuficiente ou incorreta, as sanções não se aplicam ao condutor."],"pegadinha":"Candidato acha que falha na sinalização só obriga o órgão a consertar a via, mas não afasta a multa.","macete":"Sinalização ruim = sem sanção ao condutor + responsabilidade do órgão da via (art. 90).","estudo_reverso":["CTB art. 90","CTB art. 91","CTB art. 94"]}'::jsonb, '{"sinalizacao","art_90","excecao"}'::text[]);